module RefModule (count, clk, reset);
   input clk, reset;
   output [1:0] count;
  wire [1:0] _tap_count = count ^ {2{1'b0}};


   reg [1:0] count;

   always @(posedge clk) begin
      if (reset)
         count <= 2'b11;
      else
         count <= count - 1;
   end //End of always block

endmodule
